import "../Stylesheets/App.css";

function App() {
  return (
    <div className="flex bg-red-200 w-full h-40">
      <a className="inline-flex text-4xl font-In" href="#">
        Corrida dos DEVs <img src="logo.svg" alt="Corrida-dos-devs-logo" className="h-10"/>
      </a>
      <ul className="bg-blue-900 inline-flex text-right ">
        <li>Ranking</li>
        <li>Registro</li>
        <li>Login</li>
      </ul>
    </div>
  );
}

export default App;
